import React from 'react'
import { useLyriaStream } from './hooks/useLyriaStream'
import { useScreenCapture } from './hooks/useScreenCapture'
import { useGioSession } from './hooks/useGioSession'
import { useDocumentPiP } from './hooks/useDocumentPiP'

import { HeroPanel } from './components/HeroPanel'
import { ControlPanel } from './components/ControlPanel'
import { StackSection } from './components/StackSection'

import './index.css'

function App() {
  const getApiKey = () => import.meta.env.VITE_GEMINI_API_KEY?.trim() ?? ''

  // 1. Lyria Stream Hook
  const lyria = useLyriaStream(getApiKey)

  // 2. Screen Capture Hook
  const capture = useScreenCapture({
    getApiKey,
    applyPrompt: lyria.applyPrompt,
  })

  // 3. Gio Session Hook
  const gio = useGioSession({
    getApiKey,
    fadeVolume: lyria.fadeVolume,
    latestScreenshot: capture.latestScreenshot,
  })

  // 4. Document PiP Hook
  const pip = useDocumentPiP(
    {
      status: lyria.status,
      vocalsEnabled: lyria.vocalsEnabled,
      currentMusicPrompt: capture.currentMusicPrompt,
      latestScreenshot: capture.latestScreenshot,
      lastDetectedActivity: capture.lastDetectedActivity,
      lastGeminiDecision: capture.lastGeminiDecision,
      lastAnalysisTime: capture.lastAnalysisTime,
      isGioActive: gio.isGioActive,
      gioTranscript: gio.gioTranscript,
      clipboardContent: gio.clipboardContent,
      gioError: gio.gioError,
      pendingClipboardWriteRef: gio.pendingClipboardWriteRef,
    },
    {
      playStream: lyria.playStream,
      pauseStream: lyria.pauseStream,
      toggleVocals: lyria.toggleVocals,
      startGioSession: gio.startGioSession,
      endGioSession: gio.endGioSession,
      setClipboardContent: gio.setClipboardContent,
    }
  )

  return (
    <main className="min-h-screen px-4 pb-14 pt-6 md:px-8 md:pt-12 md:pb-[56px] box-border text-center bg-[radial-gradient(circle_at_top_left,rgba(255,136,77,0.24),transparent_28%),radial-gradient(circle_at_top_right,rgba(73,166,255,0.22),transparent_24%),linear-gradient(180deg,#08131f_0%,#0e1726_45%,#101d2f_100%)] text-[#f3f4f6]">
      <HeroPanel
        status={lyria.status}
        playStream={lyria.playStream}
        pauseStream={lyria.pauseStream}
        isDocumentPiPSupported={pip.isDocumentPiPSupported}
        openDocumentPiP={pip.openDocumentPiP}
        isGioActive={gio.isGioActive}
        startGioSession={gio.startGioSession}
        endGioSession={gio.endGioSession}
        gioError={gio.gioError}
        pipMessage={pip.pipMessage}
        error={lyria.error}
      />

      <ControlPanel
        prompt={lyria.prompt}
        setPrompt={lyria.setPrompt}
        bpm={lyria.bpm}
        setBpm={lyria.setBpm}
        density={lyria.density}
        setDensity={lyria.setDensity}
        brightness={lyria.brightness}
        setBrightness={lyria.setBrightness}
        bpmOverridden={lyria.bpmOverridden}
        setBpmOverridden={lyria.setBpmOverridden}
        densityOverridden={lyria.densityOverridden}
        setDensityOverridden={lyria.setDensityOverridden}
        brightnessOverridden={lyria.brightnessOverridden}
        setBrightnessOverridden={lyria.setBrightnessOverridden}
        vocalsEnabled={lyria.vocalsEnabled}
        setVocalsEnabled={lyria.setVocalsEnabled}
        onlyBassAndDrums={lyria.onlyBassAndDrums}
        setOnlyBassAndDrums={lyria.setOnlyBassAndDrums}
        syncPrompt={lyria.syncPrompt}
        syncConfig={lyria.syncConfig}
        toggleVocals={lyria.toggleVocals}
        captureOn={capture.captureOn}
        captureStatus={capture.captureStatus}
        toggleCapture={capture.toggleCapture}
        isConnected={lyria.status === 'streaming' || lyria.status === 'paused'}
      />

      <StackSection />

      {/* Hidden elements for screen capture */}
      <video ref={capture.videoRef} style={{ display: 'none' }} muted playsInline />
      <canvas ref={capture.canvasRef} width={1280} height={720} style={{ display: 'none' }} />
    </main>
  )
}

export default App

import { useState, useRef, useEffect, useCallback } from 'react'
import { esc, type StreamStatus } from '../constants'

export interface PiPState {
  status: StreamStatus
  vocalsEnabled: boolean
  currentMusicPrompt: string
  latestScreenshot: string | null
  lastDetectedActivity: string | null
  lastGeminiDecision: string | null
  lastAnalysisTime: string | null
  isGioActive: boolean
  gioTranscript: string
  clipboardContent: string | null
  gioError: string | null
  pendingClipboardWriteRef?: React.MutableRefObject<string | null>
}

export interface PiPActions {
  playStream: () => void
  pauseStream: () => void
  toggleVocals: () => void
  startGioSession: () => void
  endGioSession: () => void
  setClipboardContent: (content: string | null) => void
}

export function useDocumentPiP(state: PiPState, actions: PiPActions) {
  const [pipMessage, setPipMessage] = useState('')
  const pipWindowRef = useRef<Window | null>(null)
  const showDebugRef = useRef(false)

  const isDocumentPiPSupported = typeof window !== 'undefined' && 'documentPictureInPicture' in window

  const closeDocumentPiP = useCallback(() => {
    pipWindowRef.current?.close()
    pipWindowRef.current = null
  }, [])

  const updatePiPContents = useCallback(() => {
    const pipWindow = pipWindowRef.current
    if (!pipWindow || pipWindow.closed) {
      pipWindowRef.current = null
      return
    }

    pipWindow.document.title = 'Gio controls'
    pipWindow.document.body.innerHTML = ''

    const style = pipWindow.document.createElement('style')
    style.textContent = `
      :root { color-scheme: dark; font-family: "Segoe UI", sans-serif; }
      body {
        margin: 0; min-height: 100vh; padding: 12px; box-sizing: border-box;
        background: radial-gradient(circle at top, rgba(249,115,22,0.24), transparent 36%),
                    linear-gradient(180deg, #08131f 0%, #101d2f 100%);
        color: #f8fafc;
      }
      .pip-shell {
        min-height: calc(100vh - 24px); display: grid; gap: 10px; align-content: start;
        border: 1px solid rgba(255,255,255,0.12); border-radius: 20px; padding: 14px;
        background: rgba(7,12,20,0.82); backdrop-filter: blur(18px);
      }
      .pip-title-bar { display: flex; align-items: center; gap: 10px; }
      .pip-title { margin: 0; font-size: 1.1rem; line-height: 1; flex: 1; }
      .pip-status {
        display: inline-flex; align-items: center; justify-content: center;
        height: 28px; border-radius: 999px; padding: 0 10px;
        font-size: 0.72rem; font-weight: 700; text-transform: capitalize;
        background: rgba(148,163,184,0.16); color: #cbd5e1; white-space: nowrap;
      }
      .pip-status.streaming { background: rgba(34,197,94,0.2); color: #86efac; }
      .pip-status.connecting { background: rgba(251,191,36,0.18); color: #fde68a; }
      .pip-status.error { background: rgba(248,113,113,0.18); color: #fca5a5; }
      .pip-now-playing {
        padding: 8px 10px; border: 1px solid rgba(249,115,22,0.22);
        border-radius: 12px; background: rgba(249,115,22,0.07);
      }
      .pip-now-playing-label {
        margin: 0 0 3px; font-size: 0.6rem; font-weight: 700;
        letter-spacing: 0.08em; text-transform: uppercase; color: #f7b267;
      }
      .pip-now-playing-value {
        margin: 0; font-size: 0.82rem; color: #f8fafc; line-height: 1.4; word-break: break-word;
      }
      .pip-gio-section { display: grid; gap: 7px; }
      .pip-gio-indicator {
        display: flex; align-items: center; gap: 8px;
        font-size: 0.78rem; font-weight: 700; color: #c4b5fd;
      }
      .pip-gio-pulse {
        width: 9px; height: 9px; border-radius: 50%; background: #a78bfa; flex-shrink: 0;
        animation: pipGioPulse 1.2s ease-in-out infinite;
      }
      @keyframes pipGioPulse {
        0%, 100% { opacity: 1; transform: scale(1); }
        50% { opacity: 0.4; transform: scale(1.5); }
      }
      .pip-gio-transcript {
        max-height: 120px; overflow-y: auto; padding: 8px 10px;
        border: 1px solid rgba(167,139,250,0.2); border-radius: 10px;
        background: rgba(139,92,246,0.07); font-size: 0.77rem;
        line-height: 1.5; color: rgba(226,232,240,0.88); word-break: break-word;
      }
      .pip-gio-clipboard {
        padding: 9px 11px; border: 1px solid rgba(52,211,153,0.25);
        border-radius: 10px; background: rgba(52,211,153,0.06); display: grid; gap: 6px;
      }
      .pip-gio-clipboard-header { display: flex; align-items: center; justify-content: space-between; }
      .pip-gio-clipboard-label {
        font-size: 0.65rem; font-weight: 700; letter-spacing: 0.07em;
        text-transform: uppercase; color: #6ee7b7;
      }
      .pip-gio-clipboard-dismiss {
        background: none; border: none !important; color: rgba(226,232,240,0.4);
        font-size: 0.8rem; padding: 0 4px; cursor: pointer; border-radius: 4px;
      }
      .pip-gio-clipboard-preview {
        font-family: ui-monospace, Consolas, monospace; font-size: 0.68rem;
        color: rgba(226,232,240,0.62); margin: 0; line-height: 1.5;
        white-space: pre-wrap; word-break: break-word;
      }
      .pip-gio-clipboard-copy {
        background: rgba(52,211,153,0.12); border: 1px solid rgba(52,211,153,0.22) !important;
        color: #6ee7b7; font-size: 0.72rem; padding: 6px 12px;
        border-radius: 8px; cursor: pointer; font-weight: 700;
        transition: background 0.15s ease, color 0.15s ease, border-color 0.15s ease;
      }
      .pip-gio-clipboard-copy:hover {
        background: rgba(52,211,153,0.22); border-color: rgba(52,211,153,0.45) !important;
      }
      .pip-gio-clipboard-copy.copied {
        background: rgba(52,211,153,0.3) !important; border-color: #34d399 !important;
        color: #fff; cursor: default;
      }
      .pip-gio-error { margin: 0; font-size: 0.74rem; color: #fca5a5; }
      .pip-gio-btn {
        width: 100%; padding: 11px 12px; border-radius: 14px;
        border: 1.5px solid rgba(139,92,246,0.35) !important;
        background: rgba(139,92,246,0.13); color: #c4b5fd;
        font: inherit; font-size: 0.82rem; font-weight: 700; cursor: pointer; user-select: none;
      }
      .pip-gio-btn.active {
        background: rgba(139,92,246,0.28);
        border-color: rgba(167,139,250,0.6) !important;
        color: #ede9fe; animation: pipGioBtn 1.5s ease-in-out infinite;
      }
      @keyframes pipGioBtn {
        0%, 100% { box-shadow: 0 0 0 0 rgba(139,92,246,0.25); }
        50% { box-shadow: 0 0 0 5px rgba(139,92,246,0); }
      }
      .pip-debug-toggle {
        width: 100%; background: rgba(255,255,255,0.04);
        border: 1px solid rgba(255,255,255,0.09) !important;
        border-radius: 10px; padding: 6px 10px; font-size: 0.68rem; font-weight: 700;
        letter-spacing: 0.07em; text-transform: uppercase;
        color: rgba(226,232,240,0.45); cursor: pointer; text-align: left;
      }
      .pip-debug-toggle:hover { background: rgba(255,255,255,0.07); color: rgba(226,232,240,0.65); }
      .pip-debug-drawer { display: none; }
      .pip-debug-drawer.open { display: grid; gap: 5px; }
      .pip-debug-row {
        padding: 7px 9px; border: 1px solid rgba(255,255,255,0.06);
        border-radius: 10px; background: rgba(0,0,0,0.28);
      }
      .pip-debug-label {
        margin: 0 0 2px; font-size: 0.58rem; font-weight: 700;
        letter-spacing: 0.08em; text-transform: uppercase; color: rgba(247,178,103,0.65);
      }
      .pip-debug-value {
        margin: 0; font-family: ui-monospace, Consolas, monospace;
        font-size: 0.7rem; color: rgba(226,232,240,0.65); line-height: 1.4; word-break: break-word;
      }
      .pip-debug-value-false { color: rgba(148,163,184,0.5); }
      .pip-debug-value-change { color: #86efac; font-weight: 700; }
      .pip-debug-thumbnail {
        max-height: 70px; width: auto; max-width: 100%; object-fit: contain;
        border-radius: 6px; display: block; border: 1px solid rgba(255,255,255,0.08);
      }
      .pip-actions { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; }
      button {
        border: 0; border-radius: 14px; padding: 11px 12px;
        font: inherit; font-size: 0.82rem; font-weight: 700; cursor: pointer;
      }
      .pip-primary { background: linear-gradient(135deg,#f97316 0%,#fb7185 100%); color: #fff7ed; }
      .pip-secondary {
        background: rgba(255,255,255,0.08); border: 1px solid rgba(255,255,255,0.12); color: #e2e8f0;
      }
      button:disabled { opacity: 0.5; cursor: not-allowed; }
    `

    const isPlayable = state.status === 'paused' || state.status === 'stopped' || state.status === 'idle'
    const playPauseLabel = state.status === 'streaming' ? 'Pause' : 'Play'
    const vocalsLabel = state.vocalsEnabled ? 'Vocals on' : 'Vocals off'

    const thumbnailHtml = state.latestScreenshot
      ? `<img class="pip-debug-thumbnail" src="${state.latestScreenshot}" alt="Last capture" />`
      : `<p class="pip-debug-value">No capture yet</p>`
    const activityHtml = state.lastDetectedActivity
      ? `<p class="pip-debug-value">${esc(state.lastDetectedActivity)}</p>`
      : `<p class="pip-debug-value">Waiting for first analysis...</p>`

    let decisionHtml: string
    if (state.lastGeminiDecision === null) {
      decisionHtml = `<p class="pip-debug-value">Waiting...</p>`
    } else if (state.lastGeminiDecision === 'FALSE') {
      decisionHtml = `<p class="pip-debug-value pip-debug-value-false">No change (FALSE)</p>`
    } else {
      decisionHtml = `<p class="pip-debug-value pip-debug-value-change">Changed to: ${esc(state.lastGeminiDecision)}</p>`
    }

    const gioIndicatorHtml = state.isGioActive
      ? `<div class="pip-gio-indicator"><div class="pip-gio-pulse"></div><span>Gio is listening...</span></div>`
      : state.gioTranscript
        ? `<div class="pip-gio-indicator"><span>✓ Gio responded</span></div>`
        : ''

    const gioTranscriptHtml = state.gioTranscript
      ? `<div class="pip-gio-transcript">${esc(state.gioTranscript)}</div>`
      : ''

    let gioClipboardHtml = ''
    if (state.clipboardContent) {
      const lines = state.clipboardContent.split('\n')
      const preview = lines.slice(0, 3).join('\n') + (lines.length > 3 ? '\n...' : '')
      gioClipboardHtml = `
        <div class="pip-gio-clipboard">
          <div class="pip-gio-clipboard-header">
            <span class="pip-gio-clipboard-label">📋 Clipboard ready</span>
            <button class="pip-gio-clipboard-dismiss" type="button">×</button>
          </div>
          <p class="pip-gio-clipboard-preview">${esc(preview)}</p>
          <button class="pip-gio-clipboard-copy" type="button">Copy</button>
        </div>`
    }
    const gioErrorHtml = state.gioError
      ? `<p class="pip-gio-error">${esc(state.gioError)}</p>`
      : ''
    const debugOpen = showDebugRef.current

    const shell = pipWindow.document.createElement('main')
    shell.className = 'pip-shell'
    shell.innerHTML = `
      <div class="pip-title-bar">
        <h1 class="pip-title">Gio controls</h1>
        <span class="pip-status ${state.status}">${state.status}</span>
      </div>
      <div class="pip-now-playing">
        <p class="pip-now-playing-label">Now playing</p>
        <p class="pip-now-playing-value">${esc(state.currentMusicPrompt)}</p>
      </div>
      <div class="pip-gio-section">
        ${gioIndicatorHtml}
        ${gioTranscriptHtml}
        ${gioClipboardHtml}
        ${gioErrorHtml}
        <button class="pip-gio-btn${state.isGioActive ? ' active' : ''}" type="button">
          ${state.isGioActive ? '🎙 Stop Gio' : 'Talk to Gio'}
        </button>
      </div>
      <button class="pip-debug-toggle" type="button">Debug ${debugOpen ? '▲' : '▼'}</button>
      <div class="pip-debug-drawer${debugOpen ? ' open' : ''}">
        <div class="pip-debug-row">
          <p class="pip-debug-label">Last screen capture</p>
          ${thumbnailHtml}
        </div>
        <div class="pip-debug-row">
          <p class="pip-debug-label">Gemini sees</p>
          ${activityHtml}
        </div>
        <div class="pip-debug-row">
          <p class="pip-debug-label">Gemini decision</p>
          ${decisionHtml}
        </div>
        <div class="pip-debug-row">
          <p class="pip-debug-label">Last analysis</p>
          <p class="pip-debug-value">${state.lastAnalysisTime ?? 'Not yet'}</p>
        </div>
      </div>
      <div class="pip-actions">
        <button class="pip-primary" type="button" ${state.status === 'connecting' ? 'disabled' : ''}>
          ${playPauseLabel}
        </button>
        <button class="pip-secondary" type="button" ${state.status === 'connecting' ? 'disabled' : ''}>
          ${vocalsLabel}
        </button>
      </div>
    `

    pipWindow.document.head.innerHTML = ''
    pipWindow.document.head.appendChild(style)
    pipWindow.document.body.appendChild(shell)

    shell.querySelector<HTMLButtonElement>('.pip-debug-toggle')?.addEventListener('click', () => {
      showDebugRef.current = !showDebugRef.current
      updatePiPContents()
    })

    const gioBtn = shell.querySelector<HTMLButtonElement>('.pip-gio-btn')
    if (gioBtn) {
      gioBtn.addEventListener('click', () => {
        if (state.isGioActive) {
          actions.endGioSession()
        } else {
          actions.startGioSession()
        }
      })
    }

    const copyBtn = shell.querySelector<HTMLButtonElement>('.pip-gio-clipboard-copy')
    if (copyBtn) {
      copyBtn.addEventListener('click', () => {
        if (!state.clipboardContent) return

        const showSuccess = () => {
          copyBtn.textContent = '✓ Copied!'
          copyBtn.classList.add('copied')
          copyBtn.disabled = true
          setTimeout(() => {
            copyBtn.textContent = 'Copy'
            copyBtn.classList.remove('copied')
            copyBtn.disabled = false
          }, 2000)
        }

        if (pipWindow.navigator?.clipboard) {
          pipWindow.navigator.clipboard.writeText(state.clipboardContent)
            .then(showSuccess)
            .catch(() => {
              try {
                const ta = pipWindow.document.createElement('textarea')
                ta.value = state.clipboardContent!
                ta.style.cssText = 'position:fixed;opacity:0;pointer-events:none'
                pipWindow.document.body.appendChild(ta)
                ta.focus(); ta.select()
                pipWindow.document.execCommand('copy')
                pipWindow.document.body.removeChild(ta)
                showSuccess()
              } catch (err) { }
            })
        } else {
          try {
            const ta = pipWindow.document.createElement('textarea')
            ta.value = state.clipboardContent!
            ta.style.cssText = 'position:fixed;opacity:0;pointer-events:none'
            pipWindow.document.body.appendChild(ta)
            ta.focus(); ta.select()
            pipWindow.document.execCommand('copy')
            pipWindow.document.body.removeChild(ta)
            showSuccess()
          } catch (err) { }
        }
      })
    }

    shell.querySelector<HTMLButtonElement>('.pip-gio-clipboard-dismiss')?.addEventListener('click', () => {
      actions.setClipboardContent(null)
    })

    shell.querySelector<HTMLButtonElement>('.pip-primary')?.addEventListener('click', () => {
      if (state.status === 'streaming') { actions.pauseStream(); return }
      if (isPlayable) actions.playStream()
    })

    shell.querySelector<HTMLButtonElement>('.pip-secondary')?.addEventListener('click', () => {
      actions.toggleVocals()
    })
  }, [state, actions])

  const openDocumentPiP = useCallback(async () => {
    if (!isDocumentPiPSupported) {
      setPipMessage('Document Picture-in-Picture is not supported in this browser.')
      return
    }
    if (pipWindowRef.current && !pipWindowRef.current.closed) {
      pipWindowRef.current.focus()
      return
    }
    try {
      const pipWindow = await window.documentPictureInPicture!.requestWindow({
        width: 340,
        height: 580,
        preferInitialWindowPlacement: true,
      })
      pipWindowRef.current = pipWindow
      setPipMessage('')
      pipWindow.addEventListener('pagehide', () => { pipWindowRef.current = null })

      pipWindow.document.addEventListener('click', () => {
        const content = state.pendingClipboardWriteRef?.current
        if (!content) return
        pipWindow.navigator.clipboard.writeText(content)
          .then(() => {
            if (state.pendingClipboardWriteRef) state.pendingClipboardWriteRef.current = null
          })
          .catch(() => { })
      }, { capture: true })

      updatePiPContents()
    } catch (pipError) {
      const message = pipError instanceof Error ? pipError.message : 'The browser blocked the Picture-in-Picture window.'
      setPipMessage(message)
    }
  }, [isDocumentPiPSupported, state.pendingClipboardWriteRef, updatePiPContents])

  useEffect(() => {
    updatePiPContents()
  }, [updatePiPContents])

  useEffect(() => {
    if (!isDocumentPiPSupported) return
    const handleVisibilityChange = () => {
      if (document.visibilityState !== 'hidden' || state.status !== 'streaming') return
      void openDocumentPiP()
    }
    const handlePageHide = () => {
      if (state.status !== 'streaming') return
      void openDocumentPiP()
    }
    document.addEventListener('visibilitychange', handleVisibilityChange)
    window.addEventListener('pagehide', handlePageHide)
    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange)
      window.removeEventListener('pagehide', handlePageHide)
    }
  }, [isDocumentPiPSupported, state.status, openDocumentPiP])

  // Expose unmount for App.tsx
  useEffect(() => {
    return () => {
      closeDocumentPiP()
    }
  }, [closeDocumentPiP])

  return {
    isDocumentPiPSupported,
    pipMessage,
    openDocumentPiP,
    closeDocumentPiP
  }
}

import { useState, useRef, useCallback, useEffect } from 'react'
import { GoogleGenAI, Modality, type Session } from '@google/genai'
import { GIO_MODEL, GIO_SYSTEM_PROMPT } from '../constants'

export function useGioSession({
  getApiKey,
  fadeVolume,
  latestScreenshot,
}: {
  getApiKey: () => string
  fadeVolume: (targetVolume: number, durationMs: number) => void
  latestScreenshot: string | null
}) {
  const [isGioActive, setIsGioActive] = useState(false)
  const [gioTranscript, setGioTranscript] = useState('')
  const [clipboardContent, setClipboardContent] = useState<string | null>(null)
  const [gioError, setGioError] = useState<string | null>(null)

  const gioSessionRef = useRef<Session | null>(null)
  const gioMicStreamRef = useRef<MediaStream | null>(null)
  const gioMicProcessorRef = useRef<{
    source: MediaStreamAudioSourceNode
    processor: ScriptProcessorNode
    context: AudioContext
  } | null>(null)
  const gioAudioContextRef = useRef<AudioContext | null>(null)
  const gioNextPlaybackTimeRef = useRef(0)
  const isGioActiveRef = useRef(false)
  const gioTranscriptRef = useRef('')
  const pendingClipboardWriteRef = useRef<string | null>(null)
  const wakeWordRecognitionRef = useRef<any>(null)
  const wakeWordTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const isUnmountingRef = useRef(false)
  const latestScreenshotRef = useRef(latestScreenshot)

  useEffect(() => {
    latestScreenshotRef.current = latestScreenshot
  }, [latestScreenshot])

  const scheduleGioAudioChunk = async (base64Data: string, mimeType?: string) => {
    if (!base64Data) return

    const rateMatch = mimeType?.match(/rate=(\d+)/i)
    const sampleRate = rateMatch ? Number(rateMatch[1]) : 24000

    if (!gioAudioContextRef.current || gioAudioContextRef.current.state === 'closed') {
      gioAudioContextRef.current = new AudioContext({ sampleRate })
      gioNextPlaybackTimeRef.current = gioAudioContextRef.current.currentTime + 0.1
    }

    const ctx = gioAudioContextRef.current
    if (ctx.state === 'suspended') await ctx.resume()

    const binary = atob(base64Data)
    const bytes = new Uint8Array(binary.length)
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i)

    const samples = new Int16Array(bytes.buffer, bytes.byteOffset, Math.floor(bytes.byteLength / 2))
    const frameCount = samples.length
    if (frameCount === 0) return

    const audioBuffer = ctx.createBuffer(1, frameCount, sampleRate)
    const channelData = audioBuffer.getChannelData(0)
    for (let i = 0; i < frameCount; i++) channelData[i] = (samples[i] ?? 0) / 32768

    const source = ctx.createBufferSource()
    source.buffer = audioBuffer
    source.connect(ctx.destination)

    const startAt = Math.max(ctx.currentTime + 0.1, gioNextPlaybackTimeRef.current)
    source.start(startAt)
    gioNextPlaybackTimeRef.current = startAt + audioBuffer.duration
  }

  const endGioSession = useCallback(async () => {
    if (!isGioActiveRef.current && !gioSessionRef.current && !gioMicStreamRef.current) return

    if (pendingClipboardWriteRef.current) {
      const toWrite = pendingClipboardWriteRef.current
      pendingClipboardWriteRef.current = null
      try {
        await navigator.clipboard.writeText(toWrite)
        console.log('[Gio] Clipboard written on session end (user gesture), length:', toWrite.length)
      } catch {
        try {
          const ta = document.createElement('textarea')
          ta.value = toWrite
          ta.style.cssText = 'position:fixed;opacity:0;pointer-events:none'
          document.body.appendChild(ta); ta.focus(); ta.select()
          document.execCommand('copy')
          document.body.removeChild(ta)
        } catch { /* ignore */ }
      }
    }

    isGioActiveRef.current = false
    setIsGioActive(false)

    if (wakeWordTimeoutRef.current) {
      clearTimeout(wakeWordTimeoutRef.current)
      wakeWordTimeoutRef.current = null
    }

    if (gioMicProcessorRef.current) {
      try {
        gioMicProcessorRef.current.processor.onaudioprocess = null
        gioMicProcessorRef.current.source.disconnect()
        gioMicProcessorRef.current.processor.disconnect()
        await gioMicProcessorRef.current.context.close()
      } catch { /* ignore */ }
      gioMicProcessorRef.current = null
    }
    if (gioMicStreamRef.current) {
      gioMicStreamRef.current.getTracks().forEach((t) => t.stop())
      gioMicStreamRef.current = null
    }

    if (gioSessionRef.current) {
      try { gioSessionRef.current.close() } catch { /* ignore */ }
      gioSessionRef.current = null
    }

    fadeVolume(1.0, 800)
  }, [fadeVolume])

  const startGioSession = useCallback(async () => {
    if (isGioActiveRef.current) return

    const apiKey = getApiKey()
    if (!apiKey) {
      setGioError('No API key configured')
      return
    }

    gioTranscriptRef.current = ''
    pendingClipboardWriteRef.current = null
    setGioTranscript('')
    setGioError(null)
    setClipboardContent(null)
    gioNextPlaybackTimeRef.current = 0

    isGioActiveRef.current = true
    setIsGioActive(true)

    fadeVolume(0.2, 600)

    try {
      const micStream = await navigator.mediaDevices.getUserMedia({ audio: true })
      gioMicStreamRef.current = micStream

      const client = new GoogleGenAI({ apiKey, apiVersion: 'v1alpha' })
      const session = await client.live.connect({
        model: GIO_MODEL,
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: GIO_SYSTEM_PROMPT,
          tools: [{
            functionDeclarations: [{
              name: 'saveToClipboard',
              description: 'Saves drafted or generated text content directly to the user\'s clipboard. Call this whenever you have composed a complete piece of content the user asked you to write.',
              parameters: {
                type: 'object',
                properties: {
                  content: {
                    type: 'string',
                    description: 'The complete text content to copy to the clipboard, ready to paste.',
                  },
                },
                required: ['content'],
              },
            }],
          }],
        },
        callbacks: {
          onmessage: (msg) => {
            const textChunks: string[] = []
            if (msg.text) textChunks.push(msg.text)
            const transcription = (msg as any).serverContent?.outputTranscription?.text
            if (transcription) textChunks.push(transcription)
            const parts = msg.serverContent?.modelTurn?.parts ?? []
            for (const part of parts) {
              if ((part as any).text) textChunks.push((part as any).text)
              if (part.inlineData?.data) {
                void scheduleGioAudioChunk(part.inlineData.data, part.inlineData.mimeType)
              }
            }
            if (textChunks.length > 0) {
              const next = gioTranscriptRef.current + textChunks.join('')
              gioTranscriptRef.current = next
              setGioTranscript(next)
            }

            const calls = (msg as any).toolCall?.functionCalls ?? []
            for (const call of calls) {
              if (call.name === 'saveToClipboard') {
                const content: string = call.args?.content ?? ''
                if (content) {
                  setClipboardContent(content)
                  pendingClipboardWriteRef.current = content
                  console.log('[Gio] saveToClipboard called, length:', content.length)
                }
                try {
                  gioSessionRef.current?.sendToolResponse({
                    functionResponses: [{
                      id: call.id,
                      name: call.name,
                      response: { output: { success: true } },
                    }],
                  })
                } catch (e) {
                  console.warn('[Gio] Tool response send failed:', e)
                }
              }
            }
          },
          onerror: (err: unknown) => {
            console.error('[Gio] Session error:', err)
            setGioError('Gio is unavailable')
            fadeVolume(1.0, 800)
            isGioActiveRef.current = false
            setIsGioActive(false)
          },
          onclose: (event?: CloseEvent) => {
            console.log('[Gio] Session closed', event?.code, event?.reason)
            gioSessionRef.current = null
            if (isGioActiveRef.current) {
              fadeVolume(1.0, 800)
              isGioActiveRef.current = false
              setIsGioActive(false)
              setGioError('Connection lost')
            }
          },
        },
      })

      gioSessionRef.current = session

      if (latestScreenshotRef.current) {
        setTimeout(() => {
          if (!gioSessionRef.current || !isGioActiveRef.current) return
          const base64Data = latestScreenshotRef.current!.replace(/^data:image\/jpeg;base64,/, '')
          try {
            gioSessionRef.current.sendClientContent({
              turns: [{
                role: 'user',
                parts: [
                  { inlineData: { mimeType: 'image/jpeg', data: base64Data } },
                  { text: "This is what the user's screen currently looks like. Use this as context for their question." },
                ],
              }],
              turnComplete: false,
            })
          } catch (e) {
            console.warn('[Gio] Screenshot context send failed:', e)
          }
        }, 500)
      }

      const micContext = new AudioContext({ sampleRate: 16000 })
      const actualRate = micContext.sampleRate
      const micSource = micContext.createMediaStreamSource(micStream)
      const processor = micContext.createScriptProcessor(2048, 1, 1)

      processor.onaudioprocess = (event: AudioProcessingEvent) => {
        if (!gioSessionRef.current || !isGioActiveRef.current) return
        const inputData = event.inputBuffer.getChannelData(0)
        const pcm16 = new Int16Array(inputData.length)
        for (let i = 0; i < inputData.length; i++) {
          const s = Math.max(-1, Math.min(1, inputData[i]))
          pcm16[i] = s < 0 ? s * 32768 : s * 32767
        }
        const bytes = new Uint8Array(pcm16.buffer)
        let binary = ''
        for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i])
        try {
          gioSessionRef.current.sendRealtimeInput({
            audio: { data: btoa(binary), mimeType: `audio/pcm;rate=${actualRate}` },
          })
        } catch { }
      }

      micSource.connect(processor)
      processor.connect(micContext.destination)
      gioMicProcessorRef.current = { source: micSource, processor, context: micContext }

    } catch (err) {
      console.error('[Gio] Error starting session:', err)
      const isPermission = err instanceof Error && (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError')
      setGioError(isPermission ? 'Microphone access denied' : 'Gio is unavailable')
      fadeVolume(1.0, 800)
      isGioActiveRef.current = false
      setIsGioActive(false)
      if (gioMicStreamRef.current) {
        gioMicStreamRef.current.getTracks().forEach((t) => t.stop())
        gioMicStreamRef.current = null
      }
    }
  }, [fadeVolume, getApiKey])

  const startGioSessionRef = useRef(startGioSession)
  const endGioSessionRef = useRef(endGioSession)
  useEffect(() => {
    startGioSessionRef.current = startGioSession
    endGioSessionRef.current = endGioSession
  }, [startGioSession, endGioSession])

  useEffect(() => {
    const SpeechRecognitionAPI = window.SpeechRecognition ?? window.webkitSpeechRecognition
    if (!SpeechRecognitionAPI) return

    const recognition: any = new SpeechRecognitionAPI()
    recognition.continuous = true
    recognition.interimResults = true
    recognition.lang = 'en-US'

    recognition.onresult = (event: any) => {
      for (let i = event.resultIndex; i < event.results.length; i++) {
        const text = event.results[i][0].transcript.toLowerCase()
        if (text.includes('hey gio') && !isGioActiveRef.current) {
          console.log('[Gio] Wake word detected')
          void startGioSessionRef.current()
          wakeWordTimeoutRef.current = setTimeout(() => {
            void endGioSessionRef.current()
          }, 15000)
        }
      }
    }

    recognition.onerror = (event: any) => {
      if (event.error !== 'no-speech') {
        console.warn('[Gio] Speech recognition error:', event.error)
      }
    }

    let wakeRestartTimer: ReturnType<typeof setTimeout> | null = null
    recognition.onend = () => {
      if (!isUnmountingRef.current) {
        wakeRestartTimer = setTimeout(() => {
          try { recognition.start() } catch { }
        }, 1000)
      }
    }

    try {
      recognition.start()
      wakeWordRecognitionRef.current = recognition
    } catch (err) { }

    return () => {
      if (wakeRestartTimer) clearTimeout(wakeRestartTimer)
      recognition.onend = null
      try { recognition.stop() } catch { }
    }
  }, [])

  useEffect(() => {
    return () => {
      isUnmountingRef.current = true
      void endGioSession()
    }
  }, [endGioSession])

  return {
    isGioActive,
    gioTranscript,
    clipboardContent,
    gioError,
    startGioSession,
    endGioSession,
    setClipboardContent,
    pendingClipboardWriteRef
  }
}

import { useRef, useState, useCallback, useEffect } from 'react'
import {
  GoogleGenAI,
  Modality,
  MusicGenerationMode,
  type LiveMusicGenerationConfig,
  type LiveMusicServerMessage,
  type LiveMusicSession,
} from '@google/genai'
import {
  MODEL,
  SAMPLE_RATE,
  CHANNELS,
  DEFAULT_BPM,
  DEFAULT_DENSITY,
  DEFAULT_BRIGHTNESS,
  DEFAULT_PROMPT,
  type StreamStatus
} from '../constants'

export function useLyriaStream(getApiKey: () => string) {
  const [prompt, setPrompt] = useState(DEFAULT_PROMPT)
  const [bpm, setBpm] = useState(DEFAULT_BPM)
  const [density, setDensity] = useState(DEFAULT_DENSITY)
  const [brightness, setBrightness] = useState(DEFAULT_BRIGHTNESS)
  const [bpmOverridden, setBpmOverridden] = useState(false)
  const [densityOverridden, setDensityOverridden] = useState(false)
  const [brightnessOverridden, setBrightnessOverridden] = useState(false)
  const [vocalsEnabled, setVocalsEnabled] = useState(false)
  const [onlyBassAndDrums, setOnlyBassAndDrums] = useState(false)
  const [status, setStatus] = useState<StreamStatus>('idle')
  const [error, setError] = useState('')

  const sessionRef = useRef<LiveMusicSession | null>(null)
  const lastAppliedConfigRef = useRef<LiveMusicGenerationConfig | null>(null)
  const audioContextRef = useRef<AudioContext | null>(null)
  const nextPlaybackTimeRef = useRef(0)
  const masterGainRef = useRef<GainNode | null>(null)
  const lyriaVolumeRef = useRef(1.0)
  const isUnmountingRef = useRef(false)

  const getConfigSummary = useCallback((): LiveMusicGenerationConfig => {
    const config: LiveMusicGenerationConfig = {
      onlyBassAndDrums,
      musicGenerationMode: vocalsEnabled
        ? MusicGenerationMode.VOCALIZATION
        : MusicGenerationMode.QUALITY,
    }
    if (bpmOverridden) config.bpm = bpm
    if (densityOverridden) config.density = density
    if (brightnessOverridden) config.brightness = brightness
    return config
  }, [bpm, bpmOverridden, brightness, brightnessOverridden, density, densityOverridden, onlyBassAndDrums, vocalsEnabled])

  const getEffectivePrompt = useCallback((basePrompt: string) =>
    vocalsEnabled ? `${basePrompt}, Vocals` : basePrompt, [vocalsEnabled])

  const applyPrompt = useCallback(async (nextPrompt: string) => {
    if (!sessionRef.current) return
    console.log('[Analysis] Lyria prompt update:', nextPrompt)
    await sessionRef.current.setWeightedPrompts({
      weightedPrompts: [{ text: getEffectivePrompt(nextPrompt), weight: 1 }],
    })
  }, [getEffectivePrompt])

  const applyConfig = useCallback(async (nextConfig = getConfigSummary()) => {
    if (!sessionRef.current) return
    await sessionRef.current.setMusicGenerationConfig({ musicGenerationConfig: nextConfig })
    const previousConfig = lastAppliedConfigRef.current
    const shouldResetContext = previousConfig !== null && previousConfig.bpm !== nextConfig.bpm
    lastAppliedConfigRef.current = nextConfig
    if (shouldResetContext) await sessionRef.current.resetContext()
  }, [getConfigSummary])

  const ensureMasterGain = useCallback((ctx: AudioContext): GainNode => {
    if (masterGainRef.current && masterGainRef.current.context === ctx) {
      return masterGainRef.current
    }
    const gain = ctx.createGain()
    gain.gain.value = lyriaVolumeRef.current
    gain.connect(ctx.destination)
    masterGainRef.current = gain
    return gain
  }, [])

  const ensureAudioContext = useCallback(async () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new AudioContext({ sampleRate: SAMPLE_RATE })
      ensureMasterGain(audioContextRef.current)
    }
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume()
    }
    return audioContextRef.current
  }, [ensureMasterGain])

  const fadeVolume = useCallback((targetVolume: number, durationMs: number) => {
    lyriaVolumeRef.current = targetVolume
    const gainNode = masterGainRef.current
    const ctx = audioContextRef.current
    if (!gainNode || !ctx || ctx.state === 'closed') return

    const now = ctx.currentTime
    gainNode.gain.cancelScheduledValues(now)
    gainNode.gain.setValueAtTime(gainNode.gain.value, now)
    gainNode.gain.linearRampToValueAtTime(targetVolume, now + durationMs / 1000)
  }, [])

  const resetPlaybackQueue = useCallback(() => {
    const audioContext = audioContextRef.current
    nextPlaybackTimeRef.current = audioContext ? audioContext.currentTime + 0.05 : 0
  }, [])

  const getSampleRateFromMimeType = (mimeType?: string) => {
    const sampleRateMatch = mimeType?.match(/rate=(\d+)/i)
    return sampleRateMatch ? Number(sampleRateMatch[1]) : SAMPLE_RATE
  }

  const schedulePcm16Chunk = useCallback(async (base64Data: string, mimeType?: string) => {
    const chunkSampleRate = getSampleRateFromMimeType(mimeType)
    const audioContext = audioContextRef.current && audioContextRef.current.sampleRate === chunkSampleRate
      ? await ensureAudioContext()
      : new AudioContext({ sampleRate: chunkSampleRate })

    if (audioContextRef.current && audioContextRef.current !== audioContext && audioContextRef.current.state !== 'closed') {
      await audioContextRef.current.close()
      masterGainRef.current = null
      resetPlaybackQueue()
    }

    audioContextRef.current = audioContext
    const masterGain = ensureMasterGain(audioContext)

    if (audioContext.state === 'suspended') {
      await audioContext.resume()
    }

    const binary = atob(base64Data)
    const bytes = new Uint8Array(binary.length)
    for (let index = 0; index < binary.length; index += 1) bytes[index] = binary.charCodeAt(index)

    const samples = new Int16Array(bytes.buffer, bytes.byteOffset, Math.floor(bytes.byteLength / 2))
    const frameCount = Math.floor(samples.length / CHANNELS)
    if (frameCount === 0) return

    const audioBuffer = audioContext.createBuffer(CHANNELS, frameCount, chunkSampleRate)
    const leftChannel = audioBuffer.getChannelData(0)
    const rightChannel = audioBuffer.getChannelData(1)

    for (let frame = 0; frame < frameCount; frame += 1) {
      const leftSample = samples[frame * CHANNELS] ?? 0
      const rightSample = samples[frame * CHANNELS + 1] ?? leftSample
      leftChannel[frame] = leftSample / 32768
      rightChannel[frame] = rightSample / 32768
    }

    const source = audioContext.createBufferSource()
    source.buffer = audioBuffer
    source.connect(masterGain)

    const startAt = Math.max(audioContext.currentTime + 0.05, nextPlaybackTimeRef.current)
    source.start(startAt)
    nextPlaybackTimeRef.current = startAt + audioBuffer.duration
  }, [ensureAudioContext, ensureMasterGain, resetPlaybackQueue])

  const stopStream = useCallback(async (nextStatus: Exclude<StreamStatus, 'connecting'> | null = 'idle') => {
    const currentSession = sessionRef.current
    sessionRef.current = null
    lastAppliedConfigRef.current = null

    if (currentSession?.close) await currentSession.close()

    nextPlaybackTimeRef.current = 0

    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
      await audioContextRef.current.close()
    }
    audioContextRef.current = null
    masterGainRef.current = null

    if (!isUnmountingRef.current && nextStatus) setStatus(nextStatus)
  }, [])

  const startStream = useCallback(async () => {
    const apiKey = getApiKey()
    if (!apiKey) {
      setError('Add VITE_GEMINI_API_KEY to your environment before starting the stream.')
      setStatus('error')
      return
    }

    setError('')
    setStatus('connecting')
    resetPlaybackQueue()

    try {
      await stopStream(null)
      await ensureAudioContext()
      resetPlaybackQueue()

      const client = new GoogleGenAI({ apiKey, apiVersion: 'v1alpha' })
      const session = await client.live.music.connect({
        model: MODEL,
        callbacks: {
          onmessage: (message: LiveMusicServerMessage) => {
            const audioChunks = message.serverContent?.audioChunks ?? []
            for (const chunk of audioChunks) {
              if (chunk.data) void schedulePcm16Chunk(chunk.data, chunk.mimeType)
            }
          },
          onerror: (sessionError: unknown) => {
            const nextError = sessionError instanceof Error ? sessionError.message : 'The music stream failed unexpectedly.'
            setError(nextError)
            setStatus('error')
          },
          onclose: () => {
            if (!isUnmountingRef.current) {
              setStatus(currentStatus => currentStatus === 'error' ? currentStatus : 'stopped')
            }
          },
        },
      })

      sessionRef.current = session
      await applyPrompt(prompt)
      await applyConfig()
      session.play()
      setStatus('streaming')
    } catch (streamError) {
      const nextError = streamError instanceof Error ? streamError.message : 'Unable to connect to the Lyria realtime model.'
      setError(nextError)
      setStatus('error')
      await stopStream(null)
    }
  }, [applyConfig, applyPrompt, ensureAudioContext, getApiKey, prompt, resetPlaybackQueue, schedulePcm16Chunk, stopStream])

  const playStream = useCallback(async () => {
    try {
      setError('')
      if (!sessionRef.current) { await startStream(); return }
      await ensureAudioContext()
      sessionRef.current.play()
      setStatus('streaming')
    } catch (playError) {
      const nextError = playError instanceof Error ? playError.message : 'Unable to resume playback.'
      setError(nextError)
      setStatus('error')
    }
  }, [ensureAudioContext, startStream])

  const pauseStream = useCallback(async () => {
    if (!sessionRef.current) return
    try {
      sessionRef.current.pause()
      if (audioContextRef.current?.state === 'running') {
        await audioContextRef.current.suspend()
      }
      setStatus('paused')
    } catch (pauseError) {
      const nextError = pauseError instanceof Error ? pauseError.message : 'Unable to pause playback.'
      setError(nextError)
      setStatus('error')
    }
  }, [])

  const toggleVocals = useCallback(async () => {
    const nextVocalsEnabled = !vocalsEnabled
    setVocalsEnabled(nextVocalsEnabled)
    if (!sessionRef.current) return

    try {
      await sessionRef.current.setWeightedPrompts({
        weightedPrompts: [{ text: nextVocalsEnabled ? `${prompt}, Vocals` : prompt, weight: 1 }],
      })
      const nextConfig: LiveMusicGenerationConfig = {
        ...getConfigSummary(),
        musicGenerationMode: nextVocalsEnabled
          ? MusicGenerationMode.VOCALIZATION
          : MusicGenerationMode.QUALITY,
      }
      await sessionRef.current.setMusicGenerationConfig({ musicGenerationConfig: nextConfig })
      lastAppliedConfigRef.current = nextConfig
    } catch (vocalsError) {
      setVocalsEnabled(!nextVocalsEnabled)
      const nextError = vocalsError instanceof Error ? vocalsError.message : 'Unable to update vocals.'
      setError(nextError)
      setStatus('error')
    }
  }, [getConfigSummary, prompt, vocalsEnabled])

  const syncPrompt = useCallback(async () => {
    if (!sessionRef.current) return
    try {
      setError('')
      await applyPrompt(prompt)
    } catch (promptError) {
      const nextError = promptError instanceof Error ? promptError.message : 'Unable to update the prompt.'
      setError(nextError)
      setStatus('error')
    }
  }, [applyPrompt, prompt])

  const syncConfig = useCallback(async () => {
    if (!sessionRef.current) return
    try {
      setError('')
      await applyConfig()
    } catch (configError) {
      const nextError = configError instanceof Error ? configError.message : 'Unable to update the generation settings.'
      setError(nextError)
      setStatus('error')
    }
  }, [applyConfig])

  useEffect(() => {
    return () => {
      isUnmountingRef.current = true
      void stopStream(null)
    }
  }, [stopStream])

  return {
    prompt, setPrompt,
    bpm, setBpm,
    density, setDensity,
    brightness, setBrightness,
    bpmOverridden, setBpmOverridden,
    densityOverridden, setDensityOverridden,
    brightnessOverridden, setBrightnessOverridden,
    vocalsEnabled, setVocalsEnabled,
    onlyBassAndDrums, setOnlyBassAndDrums,
    status, error,
    playStream, pauseStream, toggleVocals, syncPrompt, syncConfig, stopStream, applyPrompt, fadeVolume
  }
}
